screens.stateAndData:
{
  "session": {
    "loggedIn": boolean,
    "user": { id, username, displayName, avatarColor, lang, theme },
    "theme": 'light' | 'dark' (from localStorage 'fp-theme' or OS prefers-color-scheme)
  },
  "timeline": {
    "flows": [
      {
        "id": string,
        "title": string,
        "excerpt": string (first 2 lines),
        "authorId": string,
        "authorName": string,
        "authorAvatar": string,
        "authorAvatarColor": hex | null,
        "duration": number (seconds),
        "publishedAt": timestamp,
        "tag": 'Arte' | 'Cultura' | 'Ciencia' | ... (primary tag),
        "coverKind": 'escher' | 'turrell' | 'flavin' | 'collage',
        "coverSvg": SVG string,
        "likeCount": number,
        "commentCount": number,
        "liked": boolean (per user)
      },
      ...
    ]
  },
  "ui": {
    "activeTag": 'Todos' | 'Arte' | 'Cultura' | ... (chip filter),
    "visibleFlows": Flow[] (filtered by activeTag),
    "authModalOpen": boolean,
    "themeMode": 'light' | 'dark'
  },
  "interaction": {
    "playingCard": { cardId, elapsed, duration },
    "followState": { userId, isFollowing } (per user in sidebar),
    "likeState": { flowId, liked } (per card)
  },
  "realtime": {
    "flows": subscribed via Supabase Realtime (new flows, live like/comment counts),
    "notifications": unread count badge on Mensajes nav button
  }
}

{
  "UI_state": {
    "activeConversation": "string (conversation id or null)",
    "phoneView": "'list' | 'thread'",
    "recordingActive": "boolean",
    "recordingElapsed": "number (seconds × 4, increments every 250ms)",
    "transcriptOpenFor": "[voice_message_id] (which voice bubble's transcript is expanded)"
  },
  "Data": {
    "conversations": "[{ id, name, init, color, preview, time, unread }]",
    "messages": "[{ id, sender_id, kind: 'text'|'voice', body_text?, audio_url?, transcript_raw, created_at }]",
    "currentUser": "{ id, username, avatar_color }"
  },
  "Supabase queries": {
    "conversations": "SELECT * FROM conversations INNER JOIN conversation_members USING (conversation_id) WHERE user_id = {user_id} ORDER BY created_at DESC",
    "messages": "SELECT * FROM messages WHERE conversation_id = {conv_id} ORDER BY created_at ASC (with Realtime subscription)",
    "transcript_raw": "Voice messages have both audio_url and transcript_raw fields; Gemini-transcribed at creation time"
  },
  "LocalStorage": {
    "fp-theme": "'light' | 'dark' (persisted on toggle)"
  }
}
